  resident_user_id: "",
  amount_due: "",
  due_date: "",
  notes: "",
});

const proofTargetId = ref(null);
const proofFile = ref(null);
const proofForm = reactive({
  payment_method: "check",
  amount: "",
  payment_date: "",
  reference_number: "",
});

