import { computed, onMounted, reactive, ref } from "vue";

import {
  createBillingRecord,
  downloadStatement,
  getBillingRecords,
  requestRefund,
  uploadProof,
} from "../services/billingService";
import { useAuthStore } from "../stores/auth";

const auth = useAuthStore();

