function clearAuth() {
  state.token = "";
  state.username = "";
  state.role = "";

  localStorage.removeItem("hv_token");
  localStorage.removeItem("hv_username");
  localStorage.removeItem("hv_role");
}

function isAuthenticated() {
  return Boolean(state.token);
}

export function useAuthStore() {
  return {
    state,
    setAuth,
    clearAuth,
    isAuthenticated,
  };
}

