import { useAuthStore } from "../stores/auth";

const routes = [
  { path: "/", redirect: "/home" },
  { path: "/login", name: "login", component: LoginPage, meta: { public: true } },
  {
    path: "/home",
    name: "home",
    component: HomePage,
    meta: { roles: ["admin", "manager", "clerk", "dispatcher", "resident"] },
  },
  {
    path: "/dashboard",
    name: "dashboard",
